func TestScore_SupportedLanguage_StillWorks(t *testing.T) {
	// Smoke test: a realistic Go unit with good evidence must produce
	// non-empty scores (not nil / N/A) after the #25 refactoring.
	ev := []domain.Evidence{
		evidence.CodeMetrics{TotalLines: 200, CodeLines: 150, Complexity: 5}.ToEvidence(),
		evidence.LintResult{Tool: "golangci-lint", ErrorCount: 0}.ToEvidence(),
		evidence.TestResult{Tool: "go test", TotalCount: 20, PassedCount: 20, Coverage: 0.85}.ToEvidence(),
	}

	scores := engine.Score(ev, policy.EvaluationResult{Passed: true}, "go")

	// Supported language must return non-nil, non-empty scores (not N/A).
	if scores == nil {
		t.Fatal("Score returned nil for Go — supported language must produce scores")
	}
	if len(scores) == 0 {
		t.Error("expected non-empty DimensionScores for supported Go unit")
	}

	// At least one dimension must be populated with a positive score.
	hasPopulated := false
	for _, v := range scores {
		if v > 0 {
			hasPopulated = true
			break
		}
	}
	if !hasPopulated {
		t.Error("expected at least one dimension with score > 0")
	}

	// Weighted average for clean Go code should land above the F range.
	avg := scores.WeightedAverage(nil)
	if avg < 0.50 {
		t.Errorf("clean Go code average = %f, want >= 0.50 (above F / N/A range)", avg)
	}
}

func TestScore_DefaultsNotInjected(t *testing.T) {
	// Regression guard: no dimension score should equal the old hardcoded
	// default of 0.5, nor fall in the near-default band [0.49, 0.51].
	ev := []domain.Evidence{
		evidence.CodeMetrics{TotalLines: 100, CodeLines: 80, Complexity: 3}.ToEvidence(),
