	scores := engine.Score(ev, policy.EvaluationResult{Passed: true}, "go")

	for dim, val := range scores {
		if val == 0.5 {
			t.Errorf("dimension %s = 0.5 (old hardcoded default) — must not be injected", dim)
		}
		if val > 0.49 && val < 0.51 {
			t.Errorf("dimension %s = %f in [0.49, 0.51] — near old default, suspect injection", dim, val)
		}
	}
}

